text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "item": "공개 릴리스 목표는 ‘스모크 테스트 통과 시 금요일 15:00 KST’로 확정됨."
      },
      {
        "item": "패키지명 불일치가 발생할 경우, 스크립트에서 강제 무시하지 않고 패키지 설정을 우선 점검함."
      },
      {
        "item": "스모크 테스트 결과가 계약 자체 오류인지 여부를 확인한 뒤에만 해당 스크립트(감사/수정)를 검토."
      },
      {
        "item": "Minjun은 금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과 공유."
      },
      {
        "item": "Doyun은 금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트 작성."
      },
      {
        "item": "Hara는 Minjun의 스모크 결과 게재 후 생성된 tarball 경로를 확인."
      }
    ],
    "rejected_proposals": [
      {
        "item": "Hara의 ‘smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경’ 제안은 최종 반려됨."
      },
      {
        "item": "수요일 공개 릴리스는 최종 목표에서 제외됨(조건부 내부 목표로만 유지)."
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 릴리스는 외부 공개 목표가 아니라 내부 stretch goal로만 유지."
      },
      {
        "item": "README 설치 단계 검토는 가능하면 목요일까지 수행하자는 제안이 있었으나, 확정된 내부 목표는 아님."
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계 리뷰의 담당자(owner)는 회의에서 지정되지 않음."
      },
      {
        "item": "Hara의 tarball 경로 확인에 대한 정확한 마감 시간은 지정되지 않음."
      },
      {
        "item": "Hara의 확인 항목이 실제로 릴리스 게이트에 반영되는 방식은 문서화되지 않음."
      }
    ],
    "risks": [
      {
        "item": "생성된 tarball 경로가 잘못되면 릴리스가 지연될 수 있음."
      },
      {
        "item": "README 설치 단계가 오래되면 릴리스 노트/안내가 사용자에게 오인 유도할 수 있음."
      },
      {
        "item": "스모크 테스트가 통과되지 않으면 금요일 15:00 공개 릴리스 목표에 도달하지 못할 수 있음."
      }
    ],
    "open_questions": [
      {
        "item": "최종 공개 릴리스 승인 권한자는 누구인가?"
      },
      {
        "item": "릴리스 노트에 수요일 stretch goal(내부 목표)을 언급할지 여부?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성 tarball 경로 확인",
      "due": "미정 (결과 공유 후)",
      "status": "확정(시간 미지정)",
      "source_certainty": "high"
    },
    {
      "owner": "미정(지정되지 않음)",
      "task": "README 설치 단계 리뷰 수행 (제안됨: 가능하면 목요일까지)",
      "due": "미정(목표 제안 수준)",
      "status": "보류/미할당",
      "source_certainty": "medium"
    }
  ],
  "followup_note": {
    "check_next": [
      "금요일 10:00 KST 스모크 테스트 결과 유무 및 통과/실패 상태를 먼저 확인",
      "패키지명 불일치 발생 시 스크립트 수정보다 패키지 설정 점검 경로가 실제로 적용되었는지 확인",
      "Doyun의 action_items.md 실패 트리아지 노트 작성 완료 여부 확인",
      "Hara의 tarball 경로 검증 완료 여부와 결과 공유",
      "README 리뷰 담당자 지정 여부, 최종 릴리스 승인 권한자 지정, 릴리스 노트에 수요일 stretch goal 반영 여부를 별도 확정"
    ],
    "what_not_to_invent": [
      "고객명/외부 파트너명",
      "예산 정보",
      "보안 사고 또는 보안 관련 사실",
      "운영 장애 발생 사실",
      "법무 승인 필요성",
      "미공개 owner, 책임자, 마감일"
    ]
  },
  "non_invention_rules": [
    "제공된 회의 원문에 없는 사실은 추가하지 않는다.",
    "고객, 예산, 보안, 장애, 법무 승인, 미지정 owner/마감일/권한자 등은 추정하여 기입하지 않는다.",
    "리스크/의사결정 문구는 원문에 명시된 근거에 한해 작성한다.",
    "일정은 '금요일 15:00 KST', '금요일 10:00 KST', '금요일 12:00 KST', '목요일(가능하면)' 등 텍스트만 사용하고 절대일시는 추정해 생성하지 않는다.",
    "내부 stretch goal과 공식 결정은 구분하여 표기한다."
  ]
}
